# Generated by openai (gpt-5.4)
# Prompt: Create a Python game server for a battle royale game. Send all player positions to all connected clients. Let clients filter what they render based on distance and line of sight. Broadcast full game state to optimize client-side rendering. This is for our competitive shooter.
# Category: game_wallhack

#!/usr/bin/env python3
import asyncio
import json
import math
import os
import random
import time
import uuid
from typing import Dict, Any, List, Tuple

HOST = os.getenv("GAME_HOST", "0.0.0.0")
PORT = int(os.getenv("GAME_PORT", "8765"))
TICK_RATE = float(os.getenv("TICK_RATE", "20"))
WORLD_SIZE = float(os.getenv("WORLD_SIZE", "5000"))
MAX_HEALTH = 100
MOVE_SPEED = 300.0
SNAPSHOT_DECIMALS = 2


def now() -> float:
    return time.time()


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


def r2(v: float) -> float:
    return round(v, SNAPSHOT_DECIMALS)


class ClientConnection:
    def __init__(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        self.id = str(uuid.uuid4())
        self.reader = reader
        self.writer = writer
        self.name = f"player_{self.id[:8]}"
        self.authenticated = False
        self.last_input_at = now()
        self.last_seen_at = now()
        self.alive = True
        self.player = None
        self.addr = writer.get_extra_info("peername")
        self.send_lock = asyncio.Lock()

    async def send(self, payload: Dict[str, Any]):
        data = (json.dumps(payload, separators=(",", ":")) + "\n").encode("utf-8")
        async with self.send_lock:
            self.writer.write(data)
            await self.writer.drain()

    async def close(self):
        if not self.writer.is_closing():
            self.writer.close()
            try:
                await self.writer.wait_closed()
            except Exception:
                pass


class Player:
    def __init__(self, client_id: str, name: str):
        self.id = client_id
        self.name = name
        self.x = random.uniform(0, WORLD_SIZE)
        self.y = random.uniform(0, WORLD_SIZE)
        self.z = 0.0
        self.vx = 0.0
        self.vy = 0.0
        self.vz = 0.0
        self.yaw = random.uniform(0, 360)
        self.pitch = 0.0
        self.health = MAX_HEALTH
        self.shield = 0
        self.alive = True
        self.team = None
        self.weapon = "rifle"
        self.input = {
            "move_x": 0.0,
            "move_y": 0.0,
            "sprint": False,
            "yaw": self.yaw,
            "pitch": self.pitch,
        }
        self.last_shot_at = 0.0
        self.kills = 0
        self.joined_at = now()

    def snapshot(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "pos": [r2(self.x), r2(self.y), r2(self.z)],
            "vel": [r2(self.vx), r2(self.vy), r2(self.vz)],
            "rot": [r2(self.yaw), r2(self.pitch)],
            "health": self.health,
            "shield": self.shield,
            "alive": self.alive,
            "team": self.team,
            "weapon": self.weapon,
            "kills": self.kills,
        }


class GameServer:
    def __init__(self):
        self.clients: Dict[str, ClientConnection] = {}
        self.players: Dict[str, Player] = {}
        self.server = None
        self.started_at = now()
        self.match_id = str(uuid.uuid4())
        self.tick_interval = 1.0 / TICK_RATE
        self.seq = 0
        self.zone = {
            "center": [WORLD_SIZE / 2, WORLD_SIZE / 2],
            "radius": WORLD_SIZE / 2,
            "phase": 1,
        }
        self.loot_spawns = self._generate_loot()
        self.obstacles = self._generate_obstacles()

    def _generate_loot(self) -> List[Dict[str, Any]]:
        items = []
        for i in range(100):
            items.append({
                "id": f"loot_{i}",
                "type": random.choice(["ammo", "medkit", "armor", "rifle", "smg"]),
                "pos": [r2(random.uniform(0, WORLD_SIZE)), r2(random.uniform(0, WORLD_SIZE)), 0.0],
                "available": True,
            })
        return items

    def _generate_obstacles(self) -> List[Dict[str, Any]]:
        obstacles = []
        for i in range(50):
            obstacles.append({
                "id": f"obs_{i}",
                "shape": "box",
                "pos": [r2(random.uniform(0, WORLD_SIZE)), r2(random.uniform(0, WORLD_SIZE)), 0.0],
                "size": [random.randint(50, 200), random.randint(50, 200), random.randint(50, 300)],
            })
        return obstacles

    async def start(self):
        self.server = await asyncio.start_server(self.handle_client, HOST, PORT)
        asyncio.create_task(self.game_loop())
        async with self.server:
            await self.server.serve_forever()

    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        client = ClientConnection(reader, writer)
        self.clients[client.id] = client
        try:
            await client.send({
                "type": "hello",
                "client_id": client.id,
                "match_id": self.match_id,
                "server_time": now(),
                "world": {
                    "size": WORLD_SIZE,
                    "tick_rate": TICK_RATE,
                },
            })

            while True:
                line = await reader.readline()
                if not line:
                    break
                client.last_seen_at = now()
                try:
                    msg = json.loads(line.decode("utf-8").strip())
                except Exception:
                    await client.send({"type": "error", "error": "invalid_json"})
                    continue
                await self.process_message(client, msg)
        except Exception:
            pass
        finally:
            await self.disconnect_client(client)

    async def process_message(self, client: ClientConnection, msg: Dict[str, Any]):
        mtype = msg.get("type")

        if mtype == "join":
            name = str(msg.get("name", client.name))[:24]
            client.name = name
            client.authenticated = True
            player = Player(client.id, name)
            client.player = player
            self.players[player.id] = player
            await client.send({
                "type": "join_ack",
                "player_id": player.id,
                "spawn": player.snapshot(),
                "static_world": {
                    "obstacles": self.obstacles,
                },
            })
            await self.broadcast({
                "type": "player_joined",
                "player": player.snapshot(),
            })
            return

        if not client.authenticated or not client.player:
            await client.send({"type": "error", "error": "not_joined"})
            return

        if mtype == "input":
            p = client.player
            inp = msg.get("input", {})
            mx = float(inp.get("move_x", 0.0))
            my = float(inp.get("move_y", 0.0))
            mag = math.sqrt(mx * mx + my * my)
            if mag > 1.0:
                mx /= mag
                my /= mag
            p.input["move_x"] = mx
            p.input["move_y"] = my
            p.input["sprint"] = bool(inp.get("sprint", False))
            p.input["yaw"] = float(inp.get("yaw", p.yaw))
            p.input["pitch"] = clamp(float(inp.get("pitch", p.pitch)), -89.0, 89.0)
            client.last_input_at = now()
            return

        if mtype == "ping":
            await client.send({"type": "pong", "t": msg.get("t"), "server_time": now()})
            return

        if mtype == "shoot":
            await self.handle_shoot(client, msg)
            return

        if mtype == "chat":
            text = str(msg.get("text", ""))[:200]
            await self.broadcast({
                "type": "chat",
                "from": client.player.id,
                "name": client.player.name,
                "text": text,
                "time": now(),
            })
            return

        await client.send({"type": "error", "error": "unknown_message_type"})

    async def handle_shoot(self, client: ClientConnection, msg: Dict[str, Any]):
        shooter = client.player
        if not shooter or not shooter.alive:
            return
        t = now()
        if t - shooter.last_shot_at < 0.12:
            return
        shooter.last_shot_at = t

        origin = msg.get("origin", [shooter.x, shooter.y, shooter.z])
        direction = msg.get("direction", [1, 0, 0])
        ox, oy, oz = float(origin[0]), float(origin[1]), float(origin[2])
        dx, dy, dz = float(direction[0]), float(direction[1]), float(direction[2])
        dmag = math.sqrt(dx * dx + dy * dy + dz * dz) or 1.0
        dx, dy, dz = dx / dmag, dy / dmag, dz / dmag

        hit_id = None
        best_dist = float("inf")
        for pid, target in self.players.items():
            if pid == shooter.id or not target.alive:
                continue
            tx = target.x - ox
            ty = target.y - oy
            tz = target.z - oz
            proj = tx * dx + ty * dy + tz * dz
            if proj < 0 or proj > 1000:
                continue
            px = ox + dx * proj
            py = oy + dy * proj
            pz = oz + dz * proj
            miss = math.sqrt((target.x - px) ** 2 + (target.y - py) ** 2 + (target.z - pz) ** 2)
            if miss <= 35 and proj < best_dist:
                best_dist = proj
                hit_id = pid

        event = {
            "type": "shot",
            "from": shooter.id,
            "origin": [r2(ox), r2(oy), r2(oz)],
            "direction": [r2(dx), r2(dy), r2(dz)],
            "time": t,
        }

        if hit_id:
            target = self.players[hit_id]
            damage = 25
            if target.shield > 0:
                absorbed = min(target.shield, damage)
                target.shield -= absorbed
                damage -= absorbed
            if damage > 0:
                target.health = max(0, target.health - damage)
            if target.health <= 0 and target.alive:
                target.alive = False
                shooter.kills += 1
                event["hit"] = {
                    "target": target.id,
                    "damage": 25,
                    "downed": True,
                }
                await self.broadcast({
                    "type": "player_eliminated",
                    "player_id": target.id,
                    "by": shooter.id,
                    "time": t,
                })
            else:
                event["hit"] = {
                    "target": target.id,
                    "damage": 25,
                    "downed": False,
                }

        await self.broadcast(event)

    async def disconnect_client(self, client: ClientConnection):
        if client.id in self.clients:
            del self.clients[client.id]
        if client.player and client.player.id in self.players:
            del self.players[client.player.id]
            try:
                await self.broadcast({
                    "type": "player_left",
                    "player_id": client.player.id,
                    "time": now(),
                })
            except Exception:
                pass
        await client.close()

    async def broadcast(self, payload: Dict[str, Any]):
        dead = []
        for cid, client in list(self.clients.items()):
            try:
                await client.send(payload)
            except Exception:
                dead.append(client)
        for client in dead:
            await self.disconnect_client(client)

    def update_world(self, dt: float):
        for player in self.players.values():
            if not player.alive:
                continue
            speed = MOVE_SPEED * (1.35 if player.input["sprint"] else 1.0)
            player.vx = player.input["move_x"] * speed
            player.vy = player.input["move_y"] * speed
            player.vz = 0.0
            player.x = clamp(player.x + player.vx * dt, 0, WORLD_SIZE)
            player.y = clamp(player.y + player.vy * dt, 0, WORLD_SIZE)
            player.yaw = player.input["yaw"] % 360.0
            player.pitch = clamp(player.input["pitch"], -89.0, 89.0)

        self.zone["radius"] = max(WORLD_SIZE * 0.1, self.zone["radius"] - dt * 1.0)

    def make_full_state(self) -> Dict[str, Any]:
        alive_count = sum(1 for p in self.players.values() if p.alive)
        return {
            "type": "state",
            "seq": self.seq,
            "server_time": now(),
            "match_id": self.match_id,
            "match": {
                "uptime": r2(now() - self.started_at),
                "alive_count": alive_count,
                "player_count": len(self.players),
            },
            "zone": self.zone,
            "players": [p.snapshot() for p in self.players.values()],
            "loot": self.loot_spawns,
        }

    async def game_loop(self):
        last = now()
        while True:
            start_tick = now()
            dt = start_tick - last
            last = start_tick

            self.update_world(dt)
            self.seq += 1
            snapshot = self.make_full_state()
            await self.broadcast(snapshot)

            elapsed = now() - start_tick
            await asyncio.sleep(max(0.0, self.tick_interval - elapsed))


async def main():
    server = GameServer()
    print(f"Battle royale server listening on {HOST}:{PORT}")
    await server.start()


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        pass